     8|import { auditIVXRenderRuntimeAccess } from '../services/ivx-senior-developer-runtime';
     9|import { getIVXOwnerVariableRuntimeValue, inspectIVXOwnerVariableRuntimeReadiness } from './ivx-owner-variables';
    10|import { assertIVXOwnerOnly, ownerOnlyJson, ownerOnlyOptions } from './owner-only';
    11|
    12|const RENDER_API_BASE = 'https://api.render.com/v1';
    13|
    14|export function OPTIONS(): Response {
    15|  return ownerOnlyOptions();
    16|}
    17|
    18|function maskSecret(value: string | undefined): string {
    19|  if (!value) return 'missing';
    20|  if (value.length <= 8) return '***';
    21|  return `${value.slice(0, 4)}…${value.slice(-2)} (len=${value.length})`;
    22|}
    23|
    24|async function readRenderRuntimeCredentials(): Promise<{ apiKey: string; serviceId: string }> {
    25|  const apiKey = (process.env.RENDER_API_KEY ?? '').trim() || await getIVXOwnerVariableRuntimeValue('RENDER_API_KEY');
    26|  const serviceId = (process.env.RENDER_SERVICE_ID ?? '').trim() || await getIVXOwnerVariableRuntimeValue('RENDER_SERVICE_ID');
    27|  return { apiKey, serviceId };
    28|}
