    30|type RenderDeployResponse = {
    31|  id?: string;
    32|  status?: string;
    33|  trigger?: string;
    34|  createdAt?: string | null;
    35|  finishedAt?: string | null;
    36|  updatedAt?: string | null;
    37|  commit?: { id?: string; message?: string; createdAt?: string } | null;
    38|  failureReason?: string | null;
    39|};
    40|
    41|function normalizeDeploy(raw: unknown): RenderDeployResponse {
    42|  const entry = (raw && typeof raw === 'object' && 'deploy' in (raw as Record<string, unknown>))
    43|    ? (raw as { deploy: Record<string, unknown> }).deploy
    44|    : (raw as Record<string, unknown>) || {};
    45|  const commitObj = (entry.commit && typeof entry.commit === 'object')
    46|    ? (entry.commit as Record<string, unknown>)
    47|    : null;
    48|  return {
    49|    id: typeof entry.id === 'string' ? entry.id : undefined,
    50|    status: typeof entry.status === 'string' ? entry.status : undefined,
    51|    trigger: typeof entry.trigger === 'string' ? entry.trigger : undefined,
    52|    createdAt: typeof entry.createdAt === 'string' ? entry.createdAt : null,
    53|    finishedAt: typeof entry.finishedAt === 'string' ? entry.finishedAt : null,
    54|    updatedAt: typeof entry.updatedAt === 'string' ? entry.updatedAt : null,
    55|    commit: commitObj as RenderDeployResponse['commit'],
    56|    failureReason: typeof entry.failureReason === 'string' ? entry.failureReason : null,
    57|  };
    58|}
    59|
    60|export async function handleIVXRenderDeployLatestRequest(request: Request): Promise<Response> {
    61|  try {
    62|    await assertIVXOwnerOnly(request);
    63|  } catch (err) {
    64|    const message = err instanceof Error ? err.message : 'unauthorized';
    65|    return ownerOnlyJson({ ok: false, error: message }, 401);
    66|  }
    67|
    68|  const { apiKey, serviceId } = await readRenderRuntimeCredentials();
    69|  const [apiKeyReadiness, serviceIdReadiness, renderAudit] = await Promise.all([
    70|    inspectIVXOwnerVariableRuntimeReadiness('RENDER_API_KEY'),
    71|    inspectIVXOwnerVariableRuntimeReadiness('RENDER_SERVICE_ID'),
    72|    auditIVXRenderRuntimeAccess(),
    73|  ]);
    74|
    75|  const credentialReport = {
    76|    renderApiKey: {
    77|      present: apiKeyReadiness.present,
    78|      length: apiKeyReadiness.length,
    79|      source: apiKeyReadiness.source,
    80|      processEnvPresent: apiKeyReadiness.processEnvPresent,
    81|      ownerVariablesStorePresent: apiKeyReadiness.ownerVariablesStorePresent,
    82|      maskedEnvOnly: maskSecret(process.env.RENDER_API_KEY),
    83|    },
    84|    renderServiceId: {
    85|      present: serviceIdReadiness.present,
    86|      length: serviceIdReadiness.length,
    87|      source: serviceIdReadiness.source,
    88|      processEnvPresent: serviceIdReadiness.processEnvPresent,
    89|      ownerVariablesStorePresent: serviceIdReadiness.ownerVariablesStorePresent,
    90|      value: serviceId ? `${serviceId.slice(0, 4)}…${serviceId.slice(-4)}` : 'missing',
    91|    },
    92|  };
    93|
    94|  if (!apiKey || !serviceId) {
    95|    return ownerOnlyJson({
    96|      ok: false,
    97|      error: 'missing_render_credentials',
    98|      credentials: credentialReport,
    99|      renderAudit,
   100|      hint: 'RENDER_API_KEY and RENDER_SERVICE_ID must be readable from process.env or the encrypted Owner Variables runtime bridge.',
   101|      runtime: { node: process.version, platform: process.platform, timestamp: new Date().toISOString() },
   102|    }, 500);
   103|  }
   104|
   105|  let clearCache: 'do_not_clear' | 'clear' = 'do_not_clear';
   106|  try {
   107|    if (request.method === 'POST') {
   108|      const ct = request.headers.get('content-type') || '';
   109|      if (ct.includes('application/json')) {
   110|        const body = await request.json().catch(() => null) as { clearCache?: boolean } | null;
   111|        if (body && body.clearCache === true) clearCache = 'clear';
   112|      }
   113|    }
   114|  } catch {
   115|    // ignore body parse errors
   116|  }
   117|
   118|  const startedAt = new Date().toISOString();
   119|  let triggerStatus = 0;
   120|  let triggerOk = false;
   121|  let triggerErr: string | null = null;
   122|  let parsed: unknown = null;
   123|
   124|  try {
   125|    const response = await fetch(`${RENDER_API_BASE}/services/${encodeURIComponent(serviceId)}/deploys`, {
   126|      method: 'POST',
   127|      headers: {
   128|        Authorization: `Bearer ${apiKey}`,
   129|        'Content-Type': 'application/json',
   130|        Accept: 'application/json',
   131|      },
   132|      body: JSON.stringify({ clearCache }),
   133|    });
   134|    triggerStatus = response.status;
   135|    triggerOk = response.ok;
   136|    const text = await response.text();
   137|    if (text) {
   138|      try { parsed = JSON.parse(text); } catch { parsed = { raw: text.slice(0, 4000) }; }
   139|    }
   140|  } catch (err) {
   141|    triggerErr = err instanceof Error ? err.message : String(err);
   142|  }
   143|
   144|  if (!triggerOk) {
   145|    return ownerOnlyJson({
   146|      ok: false,
   147|      error: triggerErr ? 'render_api_network_error' : `render_api_http_${triggerStatus}`,
   148|      credentials: credentialReport,
   149|      renderAudit,
   150|      renderResponse: parsed,
   151|      networkError: triggerErr,
   152|      startedAt,
   153|      runtime: {
   154|        node: process.version,
   155|        platform: process.platform,
   156|        timestamp: new Date().toISOString(),
   157|        deploymentMarker: process.env.DEPLOYMENT_MARKER ?? null,
   158|      },
   159|    }, triggerStatus >= 400 && triggerStatus < 600 ? triggerStatus : 502);
   160|  }
   161|
   162|  const deploy = normalizeDeploy(parsed);
   163|  const commitSha = deploy.commit && typeof deploy.commit.id === 'string' ? deploy.commit.id : null;
   164|  const commitMessage = deploy.commit && typeof deploy.commit.message === 'string' ? deploy.commit.message : null;
   165|
   166|  return ownerOnlyJson({
   167|    ok: true,
   168|    credentials: credentialReport,
